package com.wjx871.population.keypopulation;import com.wjx871.population.common.ApiResponse;import lombok.RequiredArgsConstructor;import org.springframework.data.domain.*;import org.springframework.security.access.prepost.PreAuthorize;import org.springframework.web.bind.annotation.*;
@RestController@RequestMapping("/api/persons/{personId}/key-populations")@RequiredArgsConstructor class PersonKeyPopulationController{private final KeyPopulationService service;@GetMapping@PreAuthorize("hasAuthority('key-population:view')")ApiResponse<Page<KeyPopulationView>> list(@PathVariable Long personId,Pageable p){return ApiResponse.ok(service.byPerson(personId,p));}}
